import{_ as a,o as t,c as o,ag as n}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Scoring Games","description":"","frontmatter":{},"headers":[],"relativePath":"scoring-games/index.md","filePath":"scoring-games/index.md"}'),r={name:"scoring-games/index.md"};function i(s,e,g,l,h,c){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="scoring-games" tabindex="-1">Scoring Games <a class="header-anchor" href="#scoring-games" aria-label="Permalink to &quot;Scoring Games&quot;">​</a></h1><p>Diamond Analytics captures game data through four specialized loggers — Pitching, At-Bat, Fielding, and Baserunning. Each logger is optimized for rapid data entry during live play.</p><h2 id="starting-a-game-session" tabindex="-1">Starting a Game Session <a class="header-anchor" href="#starting-a-game-session" aria-label="Permalink to &quot;Starting a Game Session&quot;">​</a></h2><ol><li>From the dashboard tap <strong>Log Game Data</strong></li><li>Select <strong>Game</strong> as the session type</li><li>Select your opponent — choose from saved opponents or add a new one</li><li>If you have a game scheduled for today it will appear as a pre-filled option</li><li>Tap <strong>Start Game</strong></li></ol><p>You are now in the <strong>Game Hub</strong> — the central screen for all game logging.</p><h2 id="game-hub" tabindex="-1">Game Hub <a class="header-anchor" href="#game-hub" aria-label="Permalink to &quot;Game Hub&quot;">​</a></h2><p>The Game Hub is your home base during a game. From here you access:</p><ul><li><strong>Pitching Logger</strong> — log every pitch</li><li><strong>At-Bat Logger</strong> — log hitting results</li><li><strong>Fielding Logger</strong> — log defensive plays</li><li><strong>Baserunning Logger</strong> — log stolen bases and baserunning events</li><li><strong>Voice Logger</strong> — describe plays verbally for AI-powered logging</li><li><strong>Score and Inning Tracker</strong> — track the current score and inning</li></ul><h2 id="navigation-between-loggers" tabindex="-1">Navigation Between Loggers <a class="header-anchor" href="#navigation-between-loggers" aria-label="Permalink to &quot;Navigation Between Loggers&quot;">​</a></h2><p>Each logger has a <strong>back arrow</strong> in the top left to return to the Game Hub.</p><p>For related loggers you can navigate directly:</p><ul><li><strong>Pitching → Fielding</strong> — when a pitch results in a ball in play the app automatically navigates to the Fielding Logger. After logging the fielding play return to the Hub manually.</li><li><strong>At-Bat ↔ Baserunning</strong> — a direct navigation button in the top right of each logger allows quick switching between these two related loggers.</li><li><strong>Pitching ↔ Fielding</strong> — same direct navigation button in the top right.</li></ul><h2 id="who-logs-data" tabindex="-1">Who Logs Data <a class="header-anchor" href="#who-logs-data" aria-label="Permalink to &quot;Who Logs Data&quot;">​</a></h2><p>Any team member with Scorekeeper role or higher can log game data. For the best results:</p><ul><li><strong>Head Coach or Assistant Coach</strong> — manages substitutions, pitcher changes, and reviews data</li><li><strong>Scorekeeper or parent volunteer</strong> — focuses on real-time data entry</li><li><strong>Voice logging</strong> — reduces the skill required for parent volunteers significantly</li></ul>',15)])])}const p=a(r,[["render",i]]);export{u as __pageData,p as default};
